class Solution:
    def longestAlternatingSubarray(self, nums, threshold):
        n = len(nums)
        best = 0
        for l in range(n):
            if nums[l] % 2 != 0:
                continue
            for r in range(l, n):
                ok = all(nums[k] <= threshold for k in range(l, r + 1))
                if not ok:
                    break
                alt = all(nums[k] % 2 != nums[k + 1] % 2 for k in range(l, r))
                if alt:
                    best = max(best, r - l + 1)
        return best

