class Solution:
    def longestAlternatingSubarray(self, nums, threshold):
        n = len(nums)
        best = 0
        i = 0
        while i < n:
            if nums[i] % 2 != 0 or nums[i] > threshold:
                i += 1
                continue
            j = i + 1
            while j < n and nums[j] <= threshold and nums[j] % 2 != nums[j - 1] % 2:
                j += 1
            best = max(best, j - i)
            i = j
        return best

