var longestAlternatingSubarray = function(nums, threshold) {
    const n = nums.length;
    let best = 0;
    let i = 0;
    while (i < n) {
        if (nums[i] % 2 !== 0 || nums[i] > threshold) {
            i++;
            continue;
        }
        let j = i + 1;
        while (j < n && nums[j] <= threshold && nums[j] % 2 !== nums[j - 1] % 2) {
            j++;
        }
        best = Math.max(best, j - i);
        i = j;
    }
    return best;
};
